# The resource is /orders/{id}
GET    /orders/ord_123         HTTP/1.1
# Sub-resource for the cancellation event
POST   /orders/ord_123/cancellations  HTTP/1.1
Content-Type: application/json

{"reason": "customer_request"}

// Response during deprecation window — both names present
{
  "first_name": "Ada",
  "given_name": "Ada",
  "_deprecated": {
    "first_name": "Use given_name instead. Removed 2027-01-01."
  }
}

# Webhook delivery from Stripe to your server
POST /webhooks/stripe HTTP/1.1
Content-Type: application/json
Stripe-Signature: t=1746275320,v1=abc123def456...

{
  "id": "evt_1Abc2DefGhij",
  "type": "payment_intent.succeeded",
  "data": {
    "object": {
      "id": "pi_abc123",
      "amount": 4999,
      "status": "succeeded"
    }
  }
}

