{
  "type": "https://api.example.com/problems/invalid-param",
  "title": "Invalid Parameter",
  "status": 422,
  "detail": "'amount' must be a positive integer in cents.",
  "field": "amount",
  "received": -50,
  "docs_url": "https://docs.example.com/api/payments#amount"
}

// Internal API — pragmatic, field names can change
{ "usr_acct_id": "12345", "bal_cents": 4999 }

// External API — stable names, minimal surface area
{ "id": "usr_abc123", "balance": { "amount": 4999, "currency": "usd" } }
